class Solution:
    def minImpossibleOR(self, nums):
        n = len(nums)
        achievable = set()
        for mask in range(1, 1 << n):
            v = 0
            for i in range(n):
                if mask & (1 << i):
                    v |= nums[i]
            achievable.add(v)
        x = 1
        while x in achievable:
            x *= 2
        return x

